import{_ as r,C as a,o as i,c as o,E as n,w as s,a as l,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Belgium Healthcare & HRT","description":"Transgender healthcare access in Belgium","frontmatter":{"layout":"doc","title":"Belgium Healthcare & HRT","description":"Transgender healthcare access in Belgium"},"headers":[],"relativePath":"europe/belgium/healthcare.md","filePath":"europe/belgium/healthcare.md","lastUpdated":null}'),c={name:"europe/belgium/healthcare.md"};function h(u,e,p,m,g,b){const t=a("Badge");return i(),o("div",null,[n(t,{variant:"green"},{default:s(()=>[...e[0]||(e[0]=[l("Informed Consent",-1)])]),_:1}),e[1]||(e[1]=d('<h1 id="healthcare-hrt-in-belgium" tabindex="-1">Healthcare &amp; HRT in Belgium <a class="header-anchor" href="#healthcare-hrt-in-belgium" aria-label="Permalink to &quot;Healthcare &amp; HRT in Belgium&quot;">​</a></h1><h2 id="access-model" tabindex="-1">Access Model <a class="header-anchor" href="#access-model" aria-label="Permalink to &quot;Access Model&quot;">​</a></h2><p>Belgium uses an informed consent model for transgender healthcare. You can access hormone therapy through endocrinologists or specialised gender clinics without requiring a mental health assessment or referral. In practice, many doctors still request a letter from a therapist, but this is not a legal requirement.</p><p>Public healthcare (INAMI/RIZIV) covers a significant portion of transgender healthcare costs, including HRT, mental health support, and gender-affirming surgeries. Up to 85-95% of costs may be reimbursed for registered patients.</p><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>UZ Gent Gender Team</td><td>Ghent</td><td>Multidisciplinary gender clinic, HRT, surgery referrals</td></tr><tr><td>UZ Leuven Gender Clinic</td><td>Leuven</td><td>Endocrinology, psychological support, surgeries</td></tr><tr><td>CHU Saint-Pierre</td><td>Brussels</td><td>Trans healthcare, HRT, primary care</td></tr><tr><td>Erasmus Hospital</td><td>Brussels</td><td>Gender clinic, HRT, surgical options</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>Belgium is an EU member state, so prescriptions from other EU/EEA countries are generally recognised. If moving from outside the EU, you will need to see a Belgian doctor to get a local prescription. Bring a doctor&#39;s letter (translated to Dutch, French, or German) documenting your current HRT regimen.</p><p>You can carry up to a 3-month supply of HRT medications for personal use when entering Belgium with a valid prescription.</p><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>Gender-affirming surgeries are available in Belgium and are largely covered by public health insurance. Major hospitals in Ghent, Leuven, and Brussels offer top surgery, bottom surgery, and facial feminisation. Wait times for surgery are typically 6-18 months depending on the procedure and hospital.</p><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Public Cost</th><th>Private Cost</th></tr></thead><tbody><tr><td>GP/Endocrinologist visit</td><td>€25-40 (with mutuelle)</td><td>€100-150</td></tr><tr><td>HRT (monthly)</td><td>€10-30</td><td>€50-80</td></tr><tr><td>Top Surgery</td><td>Covered (~90%)</td><td>€4,000-8,000</td></tr><tr><td>Bottom Surgery</td><td>Covered (~90%)</td><td>€10,000-25,000</td></tr></tbody></table>',13))])}const T=r(c,[["render",h]]);export{y as __pageData,T as default};
